// ============================================================
// Recevoir les données du PublicationAgent
// Contrat entrée: { job, payload, access_token, channel_name,
//   diffusion_type, correlation_id, job_id }
// ============================================================
const input = $input.first().json;
const dt = input.diffusion_type;

if (!['ORGANIC', 'PAID'].includes(dt)) {
  // Retour structuré au lieu de throw — compatible PublicationAgent
  return [{ json: {
    _success: false,
    _status: 'FAILED_PUBLICATION',
    _error_code: 'INVALID_DIFFUSION_TYPE',
    _error_message: `diffusion_type inconnu: ${dt}`,
    _orphans: {},
    job_id: input.job_id || null,
    correlation_id: input.correlation_id || '',
    _route: 'ERROR'
  } }];
}

return [{ json: { ...input, _route: dt } }];

// ============================================================
// FB ORGANIC — Construction requête (UC-03 §6.1)
// Supporte : texte, image, vidéo, planification native
// ============================================================
const d = $('Initialiser Connecteur').first().json;
const payload = d.payload;
const content = payload.content;
const pp = payload.platform_params;
const page_id = pp.page_id;

const hasMedia = content.media && content.media.length > 0;
const mediaItem = hasMedia ? content.media[0] : null;
const mediaType = mediaItem ? (mediaItem.type || '').toUpperCase() : null;

// Composer le message avec hashtags
let message = content.text || '';
if (content.hashtags && Array.isArray(content.hashtags) && content.hashtags.length > 0) {
  message += '\n\n' + content.hashtags.join(' ');
}

let endpoint, body, description;

if (hasMedia && (mediaType === 'IMAGE' || mediaType === 'PHOTO')) {
  // ──── POST /{page_id}/photos ────
  endpoint = `https://graph.facebook.com/v21.0/${page_id}/photos`;
  body = { url: mediaItem.url, caption: message, published: true };
  if (mediaItem.alt_text) body.alt_text_custom = mediaItem.alt_text;
  description = 'FB ORGANIC Photo';

} else if (hasMedia && (mediaType === 'VIDEO' || mediaType === 'REEL')) {
  // ──── POST /{page_id}/videos ────
  endpoint = `https://graph.facebook.com/v21.0/${page_id}/videos`;
  body = { file_url: mediaItem.url, description: message, published: true };
  if (content.headline) body.title = content.headline;
  description = 'FB ORGANIC Video';

} else {
  // ──── POST /{page_id}/feed (texte seul ou lien) ────
  endpoint = `https://graph.facebook.com/v21.0/${page_id}/feed`;
  body = { message };
  if (content.link && content.link.url) body.link = content.link.url;
  description = 'FB ORGANIC Post';
}

// ──── Planification native Facebook (10min – 75j) ────
if (d.job && d.job.scheduled_at) {
  const scheduledTs = Math.floor(new Date(d.job.scheduled_at).getTime() / 1000);
  const now = Math.floor(Date.now() / 1000);
  const minFuture = now + 600;       // 10 min minimum
  const maxFuture = now + 6480000;   // 75 jours maximum
  if (scheduledTs > minFuture && scheduledTs < maxFuture) {
    body.published = false;
    body.scheduled_publish_time = scheduledTs;
  }
}

return [{ json: {
  ...d,
  _endpoint: endpoint,
  _body: body,
  _description: description
} }];

// ============================================================
// Traiter la réponse Facebook ORGANIC
// onError: continueRegularOutput → on reçoit toujours une sortie
// ============================================================
const resp = $input.first().json;
const prev = $('Construire requête ORGANIC').first().json;

// Succès : Facebook retourne { id: "..." }
if (resp.id) {
  return [{ json: {
    _success: true,
    _platform_post_id: String(resp.id),
    _status: 'PUBLISHED',
    _error_code: null,
    _error_message: null,
    _orphans: {},
    job_id: prev.job_id,
    correlation_id: prev.correlation_id
  } }];
}

// Échec : erreur Facebook ou erreur réseau
const fbErr = resp.error || {};
const errMsg = typeof fbErr === 'object'
  ? (fbErr.message || JSON.stringify(fbErr))
  : String(fbErr);
const errCode = fbErr.code ? `META_${fbErr.code}` : 'HTTP_ERROR';

return [{ json: {
  _success: false,
  _status: 'FAILED_PUBLICATION',
  _error_code: errCode,
  _error_message: String(errMsg).substring(0, 500),
  _orphans: {},
  job_id: prev.job_id,
  correlation_id: prev.correlation_id
} }];

// Pipeline PAID simplifié — Ad uniquement
const prev = $('Traiter réponse PAID').first().json;

return [{ json: {
  _success: prev._success,
  _platform_post_id: prev._platform_post_id || null,
  _status: prev._status,
  _error_code: prev._error_code,
  _error_message: prev._error_message,
  _orphans: {},
  job_id: prev.job_id,
  correlation_id: prev.correlation_id
} }];

// ============================================================
// CONVERGENCE ÉCHEC — toutes les branches d'erreur PAID
// Reçoit les données depuis n'importe quel Check qui échoue
// ============================================================
const d = $input.first().json;

return [{ json: {
  _success: false,
  _status: d._status || 'FAILED_PUBLICATION',
  _error_code: d._error_code || 'UNKNOWN',
  _error_message: d._error_message || 'Erreur inconnue dans le pipeline PAID',
  _orphans: d._orphans || {},
  job_id: d.job_id,
  correlation_id: d.correlation_id
} }];

// FB PAID — Validate + Préparer Ad
// Le système reçoit adset_id + creative_id déjà créés manuellement
const d = $('Initialiser Connecteur').first().json;
const payload = d.payload;
const ads = payload.ads;
const pp = payload.platform_params;

// Validation
const account_id = pp.ad_account_id || pp.account_id;
if (!account_id) {
  return [{ json: {
    ...d, _step_ok: false,
    _error_code: 'MISSING_AD_ACCOUNT_ID',
    _error_message: 'ad_account_id absent dans platform_params. Requis pour PAID.'
  }}];
}
if (!ads?.adset_id) {
  return [{ json: {
    ...d, _step_ok: false,
    _error_code: 'MISSING_ADSET_ID',
    _error_message: 'ads.adset_id absent. Créer l\'ad set manuellement avant publication.'
  }}];
}
if (!ads?.creative_id) {
  return [{ json: {
    ...d, _step_ok: false,
    _error_code: 'MISSING_CREATIVE_ID',
    _error_message: 'ads.creative_id absent. Créer le créatif manuellement avant publication.'
  }}];
}

const adBody = {
  name: `Ad — ${d.job.campaign_id || 'Ad'} — ${d.job_id}`,
  adset_id: String(ads.adset_id),
  creative: { creative_id: String(ads.creative_id) },
  status: ads.status || 'PAUSED'
};

return [{ json: {
  ...d,
  _account_id: account_id,
  _step_ok: true,
  _endpoint: `https://graph.facebook.com/v21.0/act_${account_id}/ads`,
  _body: adBody
}}];

const resp = $input.first().json;
const prev = $('PAID — Validate + Prép Ad').first().json;

if (resp.id) {
  return [{ json: {
    _success: true,
    _platform_post_id: String(resp.id),
    _status: 'PUBLISHED',
    _error_code: null,
    _error_message: null,
    job_id: prev.job_id,
    correlation_id: prev.correlation_id
  }}];
}

const fbErr = resp.error || {};
return [{ json: {
  _success: false,
  _status: 'FAILED_PUBLICATION',
  _error_code: fbErr.code ? `META_${fbErr.code}` : 'HTTP_ERROR',
  _error_message: (fbErr.message || JSON.stringify(fbErr)).substring(0, 500),
  job_id: prev.job_id,
  correlation_id: prev.correlation_id
}}];
